// src/components/NotificationBell.jsx

import React from 'react';

const NotificationBell = () => {
  return (
    <div style={{
      cursor: 'pointer',
      position: 'relative',
      fontSize: 18
    }}>
      🔔

      {/* Notification count badge */}
      <span style={{
        position: 'absolute',
        top: -6,
        right: -6,
        background: 'red',
        color: 'white',
        borderRadius: '50%',
        fontSize: 10,
        padding: '2px 6px'
      }}>
        3
      </span>
    </div>
  );
};

export default NotificationBell;
